define i8 @reduce_mul_zext_odd_lanes(<3 x i1> %x) {
  %zext = zext <3 x i1> %x to <3 x i8>
  %res = call i8 @llvm.vector.reduce.mul.v3i8(<3 x i8> %zext)
  ret i8 %res
}

